/**
 * @fileoverview LayoutEditor helpers — pure utility functions for DOM creation,
 *               HTML escaping, geometry, coordinate transforms, element lookup,
 *               group traversal, snap-guide computation, and element creation.
 *
 * Every function is stateless: it receives all data it needs through
 * parameters and returns a result without side-effects.
 *
 * @module module/LayoutEditor/helpers
 */

import razyui from '../../index.js';
import { ELEMENT_DEFAULTS } from './constants.js';

// ═══════════════════════════════════════════════
// DOM helpers
// ═══════════════════════════════════════════════

/**
 * Create an HTML element with an optional class string.
 * @param {string} tag
 * @param {string} [cls]
 * @returns {Elements}
 */
export function el(tag, cls) {
    return razyui.el(tag, cls ? { className: cls } : undefined);
}

/**
 * Escape a string for safe HTML attribute / content insertion.
 * @param {string} str
 * @returns {string}
 */
export function esc(str) {
    return String(str || '').replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/</g, '&lt;');
}

/**
 * Convert a camelCase style object to kebab-case keys.
 * razyui's `.css()` lowercases first, so camelCase keys like
 * `borderRadius` become `borderradius` (invalid). This converts
 * them to `border-radius`.
 * @param {Object} obj
 * @returns {Object}
 */
export function kebabStyle(obj) {
    if (!obj || typeof obj !== 'object') return obj;
    const out = {};
    for (const key of Object.keys(obj)) {
        out[key.replace(/[A-Z]/g, m => '-' + m.toLowerCase())] = obj[key];
    }
    return out;
}

// ═══════════════════════════════════════════════
// Geometry
// ═══════════════════════════════════════════════

/**
 * Normalise a rectangle that may have negative width / height.
 * @param {{x:number, y:number, w:number, h:number}} r
 * @returns {{x:number, y:number, w:number, h:number}}
 */
export function normRect(r) {
    return {
        x: r.w < 0 ? r.x + r.w : r.x,
        y: r.h < 0 ? r.y + r.h : r.y,
        w: Math.abs(r.w),
        h: Math.abs(r.h),
    };
}

// ═══════════════════════════════════════════════
// ID generation
// ═══════════════════════════════════════════════

/**
 * Generate a unique element ID and advance the counter on ctx.
 * @param {Object} ctx
 * @returns {string}
 */
export function genId(ctx) {
    return 'el-' + (ctx.nextId++);
}

// ═══════════════════════════════════════════════
// Coordinate transforms
// ═══════════════════════════════════════════════

/**
 * Convert client (mouse) coordinates to artboard-local coordinates.
 * @param {number} cx — clientX
 * @param {number} cy — clientY
 * @param {HTMLElement} artboard
 * @param {number} zoom
 * @returns {{x:number, y:number}}
 */
export function clientToArtboard(cx, cy, artboard, zoom) {
    const rect = artboard.getBoundingClientRect();
    return {
        x: (cx - rect.left) / zoom,
        y: (cy - rect.top) / zoom,
    };
}

/**
 * Return the viewport-center point in artboard coordinates.
 * @param {HTMLElement} canvas
 * @param {HTMLElement} artboard
 * @param {number} zoom
 * @returns {{x:number, y:number}}
 */
export function viewportCenter(canvas, artboard, zoom) {
    const rect = canvas.getBoundingClientRect();
    return clientToArtboard(
        rect.left + rect.width / 2,
        rect.top + rect.height / 2,
        artboard,
        zoom,
    );
}

// ═══════════════════════════════════════════════
// Element lookup
// ═══════════════════════════════════════════════

/**
 * Find an element by ID in the elements array.
 * @param {string} id
 * @param {Array} elements
 * @returns {object|undefined}
 */
export function findEl(id, elements) {
    return elements.find(e => e.id === id);
}

/**
 * Find the group that contains a given child element ID.
 * @param {string} childId
 * @param {Array} elements
 * @returns {object|undefined}
 */
export function findParentGroup(childId, elements) {
    return elements.find(e => e.type === 'group' && e.children?.includes(childId));
}

/**
 * Get all descendant IDs recursively for a group element.
 * @param {object} groupEl
 * @param {Array} elements
 * @returns {string[]}
 */
export function getGroupDescendants(groupEl, elements) {
    const ids = [];
    if (!groupEl.children) return ids;
    groupEl.children.forEach(cid => {
        ids.push(cid);
        const child = findEl(cid, elements);
        if (child?.type === 'group') ids.push(...getGroupDescendants(child, elements));
    });
    return ids;
}

/**
 * Recalculate a group element's bounding box from its children.
 * Mutates groupEl in place.
 * @param {object} groupEl
 * @param {Array} elements
 */
export function updateGroupBounds(groupEl, elements) {
    if (!groupEl?.children?.length) return;
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    groupEl.children.forEach(cid => {
        const child = findEl(cid, elements);
        if (!child) return;
        minX = Math.min(minX, child.x);
        minY = Math.min(minY, child.y);
        maxX = Math.max(maxX, child.x + child.w);
        maxY = Math.max(maxY, child.y + child.h);
    });
    if (minX !== Infinity) {
        groupEl.x = minX;
        groupEl.y = minY;
        groupEl.w = maxX - minX;
        groupEl.h = maxY - minY;
    }
}

// ═══════════════════════════════════════════════
// Snap guides
// ═══════════════════════════════════════════════

/**
 * Compute smart alignment snap guides and apply snap correction to a drag
 * element.  Mutates `dragEl` position and sets `ctx.guides`.
 * @param {string} dragElId — ID of the element being dragged
 * @param {Object} ctx — context
 */
export function computeGuides(dragElId, ctx) {
    if (!ctx.snapGuides) { ctx.guides = []; return; }
    const dragEl = findEl(dragElId, ctx.elements);
    if (!dragEl) return;
    const guides = [];
    const thresh = ctx.snapThreshold;

    // Artboard edges + center
    const refs = [
        { axis: 'x', pos: 0 }, { axis: 'x', pos: ctx.artboardW / 2 }, { axis: 'x', pos: ctx.artboardW },
        { axis: 'y', pos: 0 }, { axis: 'y', pos: ctx.artboardH / 2 }, { axis: 'y', pos: ctx.artboardH },
    ];

    // Other elements' edges + centers
    ctx.elements.forEach(el => {
        if (el.id === dragElId) return;
        refs.push(
            { axis: 'x', pos: el.x }, { axis: 'x', pos: el.x + el.w / 2 }, { axis: 'x', pos: el.x + el.w },
            { axis: 'y', pos: el.y }, { axis: 'y', pos: el.y + el.h / 2 }, { axis: 'y', pos: el.y + el.h },
        );
    });

    // Drag element points
    const dPoints = {
        x: [dragEl.x, dragEl.x + dragEl.w / 2, dragEl.x + dragEl.w],
        y: [dragEl.y, dragEl.y + dragEl.h / 2, dragEl.y + dragEl.h],
    };

    let snapDx = null, snapDy = null;
    refs.forEach(ref => {
        dPoints[ref.axis].forEach(dp => {
            const diff = ref.pos - dp;
            if (Math.abs(diff) <= thresh) {
                guides.push(ref);
                if (ref.axis === 'x' && (snapDx === null || Math.abs(diff) < Math.abs(snapDx))) snapDx = diff;
                if (ref.axis === 'y' && (snapDy === null || Math.abs(diff) < Math.abs(snapDy))) snapDy = diff;
            }
        });
    });

    // Apply snap correction
    if (snapDx !== null) dragEl.x += snapDx;
    if (snapDy !== null) dragEl.y += snapDy;

    ctx.guides = guides;
}

// ═══════════════════════════════════════════════
// Element creation
// ═══════════════════════════════════════════════

/**
 * Create a new layout element data object (model only, no DOM).
 * @param {string} type — element type
 * @param {Object} props — property overrides
 * @param {Object} ctx — context (needs artboardW, artboardH, nextId)
 * @returns {Object} element data object
 */
export function createElement(type, props, ctx) {
    const d = ELEMENT_DEFAULTS[type] || ELEMENT_DEFAULTS.frame;
    const newEl = {
        id: genId(ctx),
        type,
        name: props.name || (type.charAt(0).toUpperCase() + type.slice(1)),
        x: props.x ?? (ctx.artboardW / 2 - d.w / 2),
        y: props.y ?? (ctx.artboardH / 2 - d.h / 2),
        w: props.w ?? d.w,
        h: props.h ?? d.h,
        rotation: props.rotation ?? 0,
        style: { ...d.style, ...(props.style || {}) },
        content: props.content ?? d.content ?? '',
        locked: false,
        visible: true,
    };
    if (type === 'group') newEl.children = props.children || [];
    if (type === 'plugin') {
        newEl.pluginName = props.pluginName || '';
        newEl.pluginProps = { ...(props.pluginProps || {}) };
    }
    return newEl;
}
