/**
 * @fileoverview LayoutEditor state — element model operations, undo / redo,
 *               clipboard, selection-based actions, isolation mode, and
 *               artboard dimension management.
 *
 * Every exported function receives the thin `ctx` context object produced
 * by the class's `#ctx()` bridge (see index.js).
 *
 * @module module/LayoutEditor/state
 */

import razyui from '../../index.js';
import { MAX_UNDO } from './constants.js';
import {
    genId, findEl, findParentGroup, getGroupDescendants,
    updateGroupBounds, createElement,
} from './helpers.js';

// ═══════════════════════════════════════════════
// Undo / Redo
// ═══════════════════════════════════════════════

/**
 * Push a deep-copy of the current elements array onto the undo stack.
 * @param {Object} ctx
 */
export function pushUndo(ctx) {
    ctx.undoStack.push(JSON.parse(JSON.stringify(ctx.elements)));
    if (ctx.undoStack.length > MAX_UNDO) ctx.undoStack.shift();
    ctx.redoStack = [];
}

/**
 * Undo the last operation.
 * @param {Object} ctx
 */
export function undo(ctx) {
    if (!ctx.undoStack.length) return;
    ctx.redoStack.push(JSON.parse(JSON.stringify(ctx.elements)));
    ctx.elements = ctx.undoStack.pop();
    ctx.fullRender();
}

/**
 * Redo the last undone operation.
 * @param {Object} ctx
 */
export function redo(ctx) {
    if (!ctx.redoStack.length) return;
    ctx.undoStack.push(JSON.parse(JSON.stringify(ctx.elements)));
    ctx.elements = ctx.redoStack.pop();
    ctx.fullRender();
}

// ═══════════════════════════════════════════════
// Element CRUD
// ═══════════════════════════════════════════════

/**
 * Add a new element to the canvas.
 * @param {string} type
 * @param {Object} [props]
 * @param {Object} ctx
 * @returns {Object} the created element
 */
export function addElement(type, props, ctx) {
    const el = createElement(type, props || {}, ctx);
    pushUndo(ctx);
    ctx.elements.push(el);
    ctx.renderElement(el);
    ctx.setSelected([el.id]);
    ctx.refreshLayers();
    ctx.onChange();
    return el;
}

/**
 * Remove elements by IDs (including group children recursively).
 * @param {string[]} ids
 * @param {Object} ctx
 */
export function removeElements(ids, ctx) {
    pushUndo(ctx);
    // Collect all IDs to remove (including group children recursively)
    const allIds = new Set(ids);
    ids.forEach(id => {
        const el = findEl(id, ctx.elements);
        if (el?.type === 'group') {
            getGroupDescendants(el, ctx.elements).forEach(cid => allIds.add(cid));
        }
    });
    // Also remove from any parent group's children array
    ctx.elements.forEach(el => {
        if (el.type === 'group' && el.children) {
            el.children = el.children.filter(cid => !allIds.has(cid));
        }
    });
    allIds.forEach(id => {
        const dom = ctx.artboard.find(`[data-le-id="${id}"]`)[0];
        if (dom) dom.remove();
        ctx.elements = ctx.elements.filter(e => e.id !== id);
    });
    ctx.selected.clear();
    ctx.refreshLayers();
    ctx.refreshProps();
    ctx.onChange();
}

/**
 * Duplicate all currently selected elements.
 * @param {Object} ctx
 */
export function duplicateSelected(ctx) {
    if (!ctx.selected.size) return;
    pushUndo(ctx);
    const newIds = [];
    const idMap = {};
    ctx.selected.forEach(id => {
        const orig = ctx.elements.find(e => e.id === id);
        if (!orig) return;
        const dup = { ...orig, id: genId(ctx), x: orig.x + 20, y: orig.y + 20, style: { ...orig.style }, name: orig.name + ' copy' };
        idMap[orig.id] = dup.id;
        // Duplicate group children too
        if (orig.type === 'group' && orig.children) {
            const newChildren = [];
            orig.children.forEach(cid => {
                const child = findEl(cid, ctx.elements);
                if (!child) return;
                const childDup = { ...child, id: genId(ctx), x: child.x + 20, y: child.y + 20, style: { ...child.style }, name: child.name + ' copy' };
                if (child.type === 'group' && child.children) childDup.children = [...child.children]; // Nested groups — basic 1 level
                idMap[child.id] = childDup.id;
                newChildren.push(childDup.id);
                ctx.elements.push(childDup);
                ctx.renderElement(childDup);
            });
            dup.children = newChildren;
        }
        ctx.elements.push(dup);
        ctx.renderElement(dup);
        newIds.push(dup.id);
    });
    ctx.setSelected(newIds);
    ctx.refreshLayers();
    ctx.onChange();
}

// ═══════════════════════════════════════════════
// Grouping
// ═══════════════════════════════════════════════

/**
 * Group all currently selected elements into a new group.
 * @param {Object} ctx
 */
export function groupSelected(ctx) {
    if (ctx.selected.size < 2) return;
    pushUndo(ctx);
    const ids = [...ctx.selected];

    // Compute group bounding box
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    ids.forEach(id => {
        const el = findEl(id, ctx.elements);
        if (!el) return;
        minX = Math.min(minX, el.x);
        minY = Math.min(minY, el.y);
        maxX = Math.max(maxX, el.x + el.w);
        maxY = Math.max(maxY, el.y + el.h);
    });

    const group = createElement('group', {
        name: 'Group',
        x: minX, y: minY,
        w: maxX - minX, h: maxY - minY,
        children: ids,
    }, ctx);

    // Remove children from any existing parent groups
    ctx.elements.forEach(el => {
        if (el.type === 'group' && el.children) {
            el.children = el.children.filter(cid => !ids.includes(cid));
        }
    });

    // Insert group at the highest z-index position of any child
    let maxIdx = -1;
    ids.forEach(id => {
        const idx = ctx.elements.findIndex(e => e.id === id);
        if (idx > maxIdx) maxIdx = idx;
    });
    ctx.elements.splice(maxIdx + 1, 0, group);

    ctx.renderElement(group);
    ctx.setSelected([group.id]);
    ctx.refreshLayers();
    ctx.onChange();
}

/**
 * Ungroup all selected groups.
 * @param {Object} ctx
 */
export function ungroupSelected(ctx) {
    const ids = [...ctx.selected];
    const groups = ids.map(id => findEl(id, ctx.elements)).filter(el => el?.type === 'group');
    if (!groups.length) return;
    pushUndo(ctx);
    const newSel = [];
    groups.forEach(group => {
        if (group.children) newSel.push(...group.children);
        const dom = ctx.artboard.find(`[data-le-id="${group.id}"]`)[0];
        if (dom) dom.remove();
        ctx.elements = ctx.elements.filter(e => e.id !== group.id);
    });
    ctx.setSelected(newSel);
    ctx.refreshLayers();
    ctx.onChange();
}

// ═══════════════════════════════════════════════
// Layer reordering
// ═══════════════════════════════════════════════

/**
 * Reorder a layer via drag-drop in the layer panel.
 * @param {string} fromId
 * @param {string} toId
 * @param {Object} ctx
 */
export function reorderLayer(fromId, toId, ctx) {
    const fromIdx = ctx.elements.findIndex(e => e.id === fromId);
    const toIdx = ctx.elements.findIndex(e => e.id === toId);
    if (fromIdx < 0 || toIdx < 0 || fromIdx === toIdx) return;
    pushUndo(ctx);
    const [moved] = ctx.elements.splice(fromIdx, 1);
    ctx.elements.splice(toIdx, 0, moved);
    // Re-order DOM z-index
    ctx.elements.forEach((el, i) => {
        const $dom = ctx.artboard.find(`[data-le-id="${el.id}"]`);
        if ($dom.length) $dom.css('z-index', i + 1);
    });
    ctx.refreshLayers();
    ctx.onChange();
}

/**
 * Reorder selected element z-order (bring to front / send to back).
 * @param {'front'|'back'} dir
 * @param {Object} ctx
 */
export function reorderZ(dir, ctx) {
    if (ctx.selected.size !== 1) return;
    const id = [...ctx.selected][0];
    const idx = ctx.elements.findIndex(e => e.id === id);
    if (idx < 0) return;
    pushUndo(ctx);
    const [el] = ctx.elements.splice(idx, 1);
    if (dir === 'front') ctx.elements.push(el);
    else ctx.elements.unshift(el);
    ctx.elements.forEach((e, i) => {
        const $dom = ctx.artboard.find(`[data-le-id="${e.id}"]`);
        if ($dom.length) $dom.css('z-index', i + 1);
    });
    ctx.refreshLayers();
    ctx.onChange();
}

// ═══════════════════════════════════════════════
// Clipboard
// ═══════════════════════════════════════════════

/**
 * Copy selected elements into the clipboard.
 * @param {Object} ctx
 */
export function copySelected(ctx) {
    ctx.clipboard = [...ctx.selected].map(id => {
        const el = findEl(id, ctx.elements);
        return el ? JSON.parse(JSON.stringify(el)) : null;
    }).filter(Boolean);
}

/**
 * Paste from clipboard.
 * @param {Object} ctx
 */
export function paste(ctx) {
    if (!ctx.clipboard.length) return;
    pushUndo(ctx);
    const newIds = [];
    ctx.clipboard.forEach(orig => {
        const dup = { ...orig, id: genId(ctx), x: orig.x + 20, y: orig.y + 20, style: { ...orig.style }, name: orig.name + ' copy' };
        if (orig.pluginProps) dup.pluginProps = { ...orig.pluginProps };
        if (dup.type === 'group') dup.children = [];
        ctx.elements.push(dup);
        ctx.renderElement(dup);
        newIds.push(dup.id);
    });
    ctx.setSelected(newIds);
    ctx.refreshLayers();
    ctx.onChange();
}

// ═══════════════════════════════════════════════
// Nudge
// ═══════════════════════════════════════════════

/**
 * Nudge selected elements by dx/dy pixels.
 * @param {number} dx
 * @param {number} dy
 * @param {Object} ctx
 */
export function nudge(dx, dy, ctx) {
    if (!ctx.selected.size) return;
    pushUndo(ctx);
    // Collect all IDs to nudge (including group children)
    const allIds = new Set();
    ctx.selected.forEach(id => {
        allIds.add(id);
        const el = findEl(id, ctx.elements);
        if (el?.type === 'group') {
            getGroupDescendants(el, ctx.elements).forEach(cid => allIds.add(cid));
        }
    });
    allIds.forEach(id => {
        const el = findEl(id, ctx.elements);
        if (el && !el.locked) {
            el.x += dx;
            el.y += dy;
            ctx.renderElement(el);
        }
    });
    ctx.refreshProps();
    ctx.onChange();
}

// ═══════════════════════════════════════════════
// Isolation mode (edit inside group)
// ═══════════════════════════════════════════════

/**
 * Enter group isolation mode.
 * @param {Object} groupEl
 * @param {Object} ctx
 */
export function enterIsolation(groupEl, ctx) {
    if (!groupEl || groupEl.type !== 'group') return;
    ctx.isolationGroup = groupEl;
    ctx.artboard.addClass('le-isolation');
    ctx.artboard.find('.le-element').each(dom => {
        const id = dom.dataset.leId;
        const isChild = groupEl.children?.includes(id);
        const isGroup = id === groupEl.id;
        razyui(dom).toggleClass('le-iso-dimmed', !isChild && !isGroup);
    });
    ctx.setSelected([]);
    ctx.showIsolationBar(groupEl);
}

/**
 * Exit group isolation mode.
 * @param {Object} ctx
 */
export function exitIsolation(ctx) {
    if (!ctx.isolationGroup) return;
    const groupId = ctx.isolationGroup.id;
    ctx.isolationGroup = null;
    ctx.artboard.removeClass('le-isolation');
    ctx.artboard.find('.le-element').each(dom => {
        razyui(dom).removeClass('le-iso-dimmed');
    });
    const bar = ctx.canvas.find('.le-iso-bar')[0];
    if (bar) bar.remove();
    ctx.setSelected([groupId]);
    const g = findEl(groupId, ctx.elements);
    if (g) { updateGroupBounds(g, ctx.elements); ctx.renderElement(g); }
}

// ═══════════════════════════════════════════════
// Artboard
// ═══════════════════════════════════════════════

/**
 * Set artboard dimensions.
 * @param {number} w
 * @param {number} h
 * @param {Object} ctx
 */
export function setArtboard(w, h, ctx) {
    w = Math.max(100, Math.round(w));
    h = Math.max(100, Math.round(h));
    if (w === ctx.artboardW && h === ctx.artboardH) return;
    ctx.artboardW = w;
    ctx.artboardH = h;
    ctx.artboard.css('width', w + 'px').css('height', h + 'px');
    ctx.updateArtboardLabel();
    ctx.onChange();
}

// ═══════════════════════════════════════════════
// Plugin element
// ═══════════════════════════════════════════════

/**
 * Add a plugin element at center of viewport.
 * @param {Object} plugin
 * @param {Object} ctx
 * @returns {Object} created element
 */
export function addPluginElement(plugin, ctx) {
    const center = ctx.viewportCenter();
    const d = plugin.defaults || {};
    const el = createElement('plugin', {
        name: plugin.label || plugin.name,
        x: center.x - (d.w || 200) / 2,
        y: center.y - (d.h || 100) / 2,
        w: d.w || 200,
        h: d.h || 100,
        style: { ...(d.style || {}) },
        content: d.content || '',
    }, ctx);
    el.pluginName = plugin.name;
    el.pluginProps = {};
    if (plugin.properties) {
        plugin.properties.forEach(p => {
            if (p.default !== undefined) el.pluginProps[p.name] = p.default;
        });
    }
    pushUndo(ctx);
    ctx.elements.push(el);
    ctx.renderElement(el);
    ctx.setSelected([el.id]);
    ctx.refreshLayers();
    ctx.onChange();
    return el;
}
