/**
 * @fileoverview LayoutEditor — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — config defaults, artboard presets, element-type defaults
 *   helpers.js   — pure utility functions (DOM, geometry, element lookup)
 *   state.js     — undo / redo, element CRUD, clipboard, grouping, isolation
 *   view.js      — DOM construction, rendering, panels, palette, zoom / pan
 *   events.js    — toolbar, canvas pointer, keyboard, context menu
 *
 * @module module/LayoutEditor
 */

import { default as razyui } from '../../index.js';

// ── Constants ───────────────────────────────────────────────────
import { DEFAULTS, ARTBOARD_PRESETS } from './constants.js';

// ── Helpers ─────────────────────────────────────────────────────
import { clientToArtboard, viewportCenter } from './helpers.js';

// ── State ───────────────────────────────────────────────────────
import {
    pushUndo,
    undo              as undoOp,
    redo              as redoOp,
    addElement,
    removeElements,
    duplicateSelected,
    groupSelected,
    ungroupSelected,
    reorderLayer,
    reorderZ,
    copySelected,
    paste,
    nudge,
    enterIsolation,
    exitIsolation,
    setArtboard,
    addPluginElement,
} from './state.js';

// ── View ────────────────────────────────────────────────────────
import {
    buildDOM,
    renderElement,
    fullRender,
    setSelected,
    toggleSelect,
    refreshLayers,
    refreshProps,
    refreshGuides,
    clearGuides,
    refreshPalette,
    updatePropValues,
    showIsolationBar,
    updateArtboardLabel,
    setZoom,
    applyTransform,
    centerArtboard,
    fitToView,
    toggleGrid,
    exportJSON,
    closeColorPopupsCtx,
} from './view.js';

// ── Events ──────────────────────────────────────────────────────
import { bindToolbar, bindCanvas, bindKeyboard, bindViewDelegation } from './events.js';


// ═════════════════════════════════════════════════════════════════
// LayoutEditor class
// ═════════════════════════════════════════════════════════════════

/**
 * LayoutEditor — Wix/Figma-style visual layout builder
 *
 * ┌─────────────────────────────────────────────────────────────┐
 * │  Toolbar   (undo ↩ redo ↪ │ zoom │ preview │ export)       │
 * ├──────────┬──────────────────────────────────┬───────────────┤
 * │  Layers  │  Canvas (infinite / zoom/pan)    │  Properties   │
 * │  panel   │  ┌─────────────────────────┐     │  panel        │
 * │          │  │  Frame / artboard       │     │  ┌──────────┐ │
 * │  ▸ Root  │  │  ┌──────┐ ┌─────────┐  │     │  │ X:  120  │ │
 * │   ▸ Hdr  │  │  │ Text │ │  Image  │  │     │  │ Y:   40  │ │
 * │   ▸ Body │  │  └──────┘ └─────────┘  │     │  │ W:  200  │ │
 * │   ▸ Ftr  │  └─────────────────────────┘     │  │ H:  100  │ │
 * │          │                                  │  └──────────┘ │
 * └──────────┴──────────────────────────────────┴───────────────┘
 */
class LayoutEditor {

    /** Artboard dimension presets (backward-compat static). */
    static ARTBOARD_PRESETS = ARTBOARD_PRESETS;

    // ── Private fields ──────────────────────────────────────────
    #container = null;
    #destroyed = false;
    #config    = {};
    #elements  = [];           // layout elements
    #selected  = new Set();    // selected IDs
    #collapsedGroups = new Set();
    #hoveredId       = null;
    #clipboard       = [];
    #undoStack       = [];
    #redoStack       = [];
    #zoom            = 1;
    #panX            = 0;
    #panY            = 0;
    #isPanning       = false;
    #panStart        = null;
    #isDragging      = false;
    #dragStart       = null;
    #dragOffsets     = null;
    #isResizing      = false;
    #resizeHandle    = null;
    #resizeStart     = null;
    #isSelecting     = false;
    #selectRect      = null;
    #gridSize        = DEFAULTS.gridSize;
    #snapToGrid      = DEFAULTS.snapToGrid;
    #snapGuides      = DEFAULTS.snapGuides;
    #snapThreshold   = DEFAULTS.snapThreshold;
    #artboardW       = DEFAULTS.artboardW;
    #artboardH       = DEFAULTS.artboardH;
    #nextId          = 1;
    #guides          = [];
    #_cpInstances    = [];
    #plugins         = [];
    #isolationGroup  = null;

    // ── DOM refs ────────────────────────────────────────────────
    #root            = null;
    #toolbar         = null;
    #layerPanel      = null;
    #canvas          = null;
    #artboard        = null;
    #propPanel       = null;
    #selectionBox    = null;
    #guidesOverlay   = null;
    #zoomLabel       = null;
    #palettePanel    = null;
    #contextMenuEl   = null;

    // ── ctx cache ───────────────────────────────────────────────
    #_ctx = null;

    // ── AbortController for global listeners ────────────────────
    #eventAC = new AbortController();

    // ─────────────────────────────────────────────────────────────
    // Constructor
    // ─────────────────────────────────────────────────────────────
    /**
     * Creates a new LayoutEditor instance.
     * @param {string|Element} selector - The container element or selector.
     * @param {Object} [config={}] - Configuration options.
     * @param {number} [config.width=1200] - Artboard width.
     * @param {number} [config.height=800] - Artboard height.
     * @param {boolean} [config.showGrid=true] - Show grid overlay.
     * @param {number} [config.gridSize=20] - Grid spacing in px.
     * @param {boolean} [config.snapToGrid=false] - Snap elements to grid.
     * @param {boolean} [config.snapGuides=true] - Show smart alignment guides.
     * @param {number} [config.snapThreshold=5] - Snap distance in px.
     * @param {Object} [config.data] - Initial layout JSON to load.
     * @param {Function} [config.onChange] - Callback triggered on any change.
     */
    constructor(selector, config = {}) {
        const el = razyui(selector);
        if (!el.length) {
            console.warn('LayoutEditor: element not found \u2192', selector);
            return;
        }
        this.#container    = el[0];
        this.#config       = config;
        this.#artboardW    = config.width         || DEFAULTS.artboardW;
        this.#artboardH    = config.height        || DEFAULTS.artboardH;
        this.#gridSize     = config.gridSize      || DEFAULTS.gridSize;
        this.#snapToGrid   = config.snapToGrid   ?? DEFAULTS.snapToGrid;
        this.#snapGuides   = config.snapGuides   ?? DEFAULTS.snapGuides;
        this.#snapThreshold = config.snapThreshold || DEFAULTS.snapThreshold;

        const ctx = this.#ctx();

        // 1. Build DOM
        buildDOM(ctx);

        // 2. Bind events
        bindToolbar(ctx);
        bindCanvas(ctx);
        bindViewDelegation(ctx);

        // 3. Populate palette
        refreshPalette(ctx);

        // 4. Initial transform
        centerArtboard(ctx);

        // 5. Load initial data
        if (config.data) this.load(config.data);

        // 6. Keyboard shortcuts (global)
        bindKeyboard(ctx);
    }

    // ─────────────────────────────────────────────────────────────
    // #ctx() — shared context bridge for sub-modules
    // ─────────────────────────────────────────────────────────────
    #ctx() {
        if (this.#_ctx) return this.#_ctx;
        const self = this;
        const ctx = {
            razyui,

            // ── AbortController signal ──────────────────────────
            get signal()          { return self.#eventAC.signal; },

            // ── Config ──────────────────────────────────────────
            get config()          { return self.#config; },
            get container()       { return self.#container; },

            // ── Elements & selection ────────────────────────────
            get elements()        { return self.#elements; },
            set elements(v)       { self.#elements = v; },
            get selected()        { return self.#selected; },
            get collapsedGroups() { return self.#collapsedGroups; },
            get hoveredId()       { return self.#hoveredId; },
            set hoveredId(v)      { self.#hoveredId = v; },
            get clipboard()       { return self.#clipboard; },
            set clipboard(v)      { self.#clipboard = v; },

            // ── Undo / Redo ─────────────────────────────────────
            get undoStack()       { return self.#undoStack; },
            get redoStack()       { return self.#redoStack; },
            set redoStack(v)      { self.#redoStack = v; },

            // ── Zoom / Pan ──────────────────────────────────────
            get zoom()            { return self.#zoom; },
            set zoom(v)           { self.#zoom = v; },
            get panX()            { return self.#panX; },
            set panX(v)           { self.#panX = v; },
            get panY()            { return self.#panY; },
            set panY(v)           { self.#panY = v; },
            get isPanning()       { return self.#isPanning; },
            set isPanning(v)      { self.#isPanning = v; },
            get panStart()        { return self.#panStart; },
            set panStart(v)       { self.#panStart = v; },

            // ── Drag ────────────────────────────────────────────
            get isDragging()      { return self.#isDragging; },
            set isDragging(v)     { self.#isDragging = v; },
            get dragStart()       { return self.#dragStart; },
            set dragStart(v)      { self.#dragStart = v; },
            get dragOffsets()     { return self.#dragOffsets; },
            set dragOffsets(v)    { self.#dragOffsets = v; },

            // ── Resize ──────────────────────────────────────────
            get isResizing()      { return self.#isResizing; },
            set isResizing(v)     { self.#isResizing = v; },
            get resizeHandle()    { return self.#resizeHandle; },
            set resizeHandle(v)   { self.#resizeHandle = v; },
            get resizeStart()     { return self.#resizeStart; },
            set resizeStart(v)    { self.#resizeStart = v; },

            // ── Selection box ───────────────────────────────────
            get isSelecting()     { return self.#isSelecting; },
            set isSelecting(v)    { self.#isSelecting = v; },
            get selectRect()      { return self.#selectRect; },
            set selectRect(v)     { self.#selectRect = v; },

            // ── Grid / snap ─────────────────────────────────────
            get gridSize()        { return self.#gridSize; },
            set gridSize(v)       { self.#gridSize = v; },
            get snapToGrid()      { return self.#snapToGrid; },
            set snapToGrid(v)     { self.#snapToGrid = v; },
            get snapGuides()      { return self.#snapGuides; },
            set snapGuides(v)     { self.#snapGuides = v; },
            get snapThreshold()   { return self.#snapThreshold; },

            // ── Artboard ────────────────────────────────────────
            get artboardW()       { return self.#artboardW; },
            set artboardW(v)      { self.#artboardW = v; },
            get artboardH()       { return self.#artboardH; },
            set artboardH(v)      { self.#artboardH = v; },
            get nextId()          { return self.#nextId; },
            set nextId(v)         { self.#nextId = v; },

            // ── Guides ──────────────────────────────────────────
            get guides()          { return self.#guides; },
            set guides(v)         { self.#guides = v; },

            // ── Color pickers ───────────────────────────────────
            get _cpInstances()    { return self.#_cpInstances; },

            // ── Plugins ─────────────────────────────────────────
            get plugins()         { return self.#plugins; },
            set plugins(v)        { self.#plugins = v; },

            // ── Isolation ───────────────────────────────────────
            get isolationGroup()  { return self.#isolationGroup; },
            set isolationGroup(v) { self.#isolationGroup = v; },

            // ── DOM refs (get / set) ────────────────────────────
            get toolbar()         { return self.#toolbar; },
            set toolbar(v)        { self.#toolbar = v; },
            get layerPanel()      { return self.#layerPanel; },
            set layerPanel(v)     { self.#layerPanel = v; },
            get canvas()          { return self.#canvas; },
            set canvas(v)         { self.#canvas = v; },
            get artboard()        { return self.#artboard; },
            set artboard(v)       { self.#artboard = v; },
            get propPanel()       { return self.#propPanel; },
            set propPanel(v)      { self.#propPanel = v; },
            get selectionBox()    { return self.#selectionBox; },
            set selectionBox(v)   { self.#selectionBox = v; },
            get guidesOverlay()   { return self.#guidesOverlay; },
            set guidesOverlay(v)  { self.#guidesOverlay = v; },
            get zoomLabel()       { return self.#zoomLabel; },
            set zoomLabel(v)      { self.#zoomLabel = v; },
            get palettePanel()    { return self.#palettePanel; },
            set palettePanel(v)   { self.#palettePanel = v; },
            get contextMenuEl()   { return self.#contextMenuEl; },
            set contextMenuEl(v)  { self.#contextMenuEl = v; },
        };

        // ── Method bridges (state operations) ───────────────────
        ctx.pushUndo          = ()            => pushUndo(ctx);
        ctx.undo              = ()            => undoOp(ctx);
        ctx.redo              = ()            => redoOp(ctx);
        ctx.addElement        = (t, p)        => addElement(t, p, ctx);
        ctx.removeElements    = (ids)         => removeElements(ids, ctx);
        ctx.duplicateSelected = ()            => duplicateSelected(ctx);
        ctx.groupSelected     = ()            => groupSelected(ctx);
        ctx.ungroupSelected   = ()            => ungroupSelected(ctx);
        ctx.reorderLayer      = (from, to)    => reorderLayer(from, to, ctx);
        ctx.reorderZ          = (dir)         => reorderZ(dir, ctx);
        ctx.copySelected      = ()            => copySelected(ctx);
        ctx.paste             = ()            => paste(ctx);
        ctx.nudge             = (dx, dy)      => nudge(dx, dy, ctx);
        ctx.enterIsolation    = (g)           => enterIsolation(g, ctx);
        ctx.exitIsolation     = ()            => exitIsolation(ctx);
        ctx.setArtboardDims   = (w, h)        => setArtboard(w, h, ctx);
        ctx.addPluginElement  = (p)           => addPluginElement(p, ctx);

        // ── Method bridges (view operations) ────────────────────
        ctx.renderElement     = (el)          => renderElement(el, ctx);
        ctx.fullRender        = ()            => fullRender(ctx);
        ctx.setSelected       = (ids)         => setSelected(ids, ctx);
        ctx.toggleSelect      = (id, add)     => toggleSelect(id, add, ctx);
        ctx.refreshLayers     = ()            => refreshLayers(ctx);
        ctx.refreshProps      = ()            => refreshProps(ctx);
        ctx.refreshGuides     = ()            => refreshGuides(ctx);
        ctx.clearGuides       = ()            => clearGuides(ctx);
        ctx.refreshPalette    = ()            => refreshPalette(ctx);
        ctx.updatePropValues  = ()            => updatePropValues(ctx);
        ctx.showIsolationBar  = (g)           => showIsolationBar(g, ctx);
        ctx.updateArtboardLabel = ()          => updateArtboardLabel(ctx);
        ctx.setZoom           = (z, cx, cy)   => setZoom(z, cx, cy, ctx);
        ctx.applyTransform    = ()            => applyTransform(ctx);
        ctx.centerArtboard    = ()            => centerArtboard(ctx);
        ctx.fitToView         = ()            => fitToView(ctx);
        ctx.toggleGrid        = ()            => toggleGrid(ctx);
        ctx.exportJSON        = ()            => exportJSON(ctx);
        ctx.closeColorPopups  = ()            => closeColorPopupsCtx(ctx);

        // ── Method bridges (helpers) ────────────────────────────
        ctx.viewportCenter    = ()            => viewportCenter(self.#canvas[0], self.#artboard[0], self.#zoom);
        ctx.clientToArtboard  = (cx, cy)      => clientToArtboard(cx, cy, self.#artboard[0], self.#zoom);

        // ── Callbacks ───────────────────────────────────────────
        ctx.onChange = () => {
            if (typeof self.#config.onChange === 'function') {
                self.#config.onChange(self.export());
            }
        };
        ctx.exportData = () => self.export();

        this.#_ctx = ctx;
        return ctx;
    }

    // ═══════════════════════════════════════════════════════════════
    // PUBLIC API
    // ═══════════════════════════════════════════════════════════════

    /** 
     * Undo the last operation. 
     */
    undo() { undoOp(this.#ctx()); }

    /** 
     * Redo the last undone operation. 
     */
    redo() { redoOp(this.#ctx()); }

    /** 
     * Add an element programmatically. 
     * @param {string} type - The type of element to add.
     * @param {Object} props - The properties of the element.
     * @returns {Object} The added element.
     */
    add(type, props) { return addElement(type, props, this.#ctx()); }

    /** 
     * Remove elements by ID. 
     * @param {...string} ids - The IDs of the elements to remove.
     */
    remove(...ids) { removeElements(ids, this.#ctx()); }

    /** 
     * Get selected element IDs. 
     * @returns {string[]} An array of selected element IDs.
     */
    getSelected() { return [...this.#selected]; }

    /** 
     * Set zoom level (0.1–5). 
     * @param {number} z - The zoom level.
     */
    setZoom(z) { setZoom(z, undefined, undefined, this.#ctx()); }

    /** 
     * Get current zoom. 
     * @returns {number} The current zoom level.
    /** 
     * Get current zoom. 
     * @returns {number} The current zoom level.
     */
    getZoom() { return this.#zoom; }

    /** 
     * Get all elements (deep copy). 
     * @returns {Object[]} An array of all elements.
     */
    getElements() { return JSON.parse(JSON.stringify(this.#elements)); }

    /** 
     * Set artboard dimensions. 
     * @param {number} w - The width of the artboard.
     * @param {number} h - The height of the artboard.
     */
    setArtboard(w, h) { setArtboard(w, h, this.#ctx()); refreshProps(this.#ctx()); }

    /** 
     * Open export popup. 
     */
    exportPopup() { exportJSON(this.#ctx()); }

    /** 
     * Get artboard dimensions. 
     * @returns {Object} An object containing the width and height of the artboard.
     */
    getArtboard() { return { width: this.#artboardW, height: this.#artboardH }; }

    /** 
     * Export layout data as JSON-safe object. 
     * @returns {Object} The exported layout data.
     */
    export() {
        return {
            artboard: { width: this.#artboardW, height: this.#artboardH },
            elements: JSON.parse(JSON.stringify(this.#elements)),
        };
    }

    /** 
     * Load layout data from a JSON object. 
     * @param {Object} data - The layout data to load.
     */
    load(data) {
        if (!data?.elements) return;
        const ctx = this.#ctx();
        ctx.elements = data.elements;
        ctx.artboardW = data.artboard?.width || ctx.artboardW;
        ctx.artboardH = data.artboard?.height || ctx.artboardH;
        ctx.artboard.css('width', ctx.artboardW + 'px');
        ctx.artboard.css('height', ctx.artboardH + 'px');
        // Update nextId
        ctx.nextId = ctx.elements.reduce((max, el) => {
            const n = parseInt(el.id.replace('el-', ''), 10);
            return isNaN(n) ? max : Math.max(max, n + 1);
        }, 1);
        ctx.fullRender();
        ctx.centerArtboard();
    }

    /** 
     * Get the control API object. 
     * @returns {Object} The control API object.
     */
    getControl() {
        const self = this;
        return {
            add:              (type, props)  => self.add(type, props),
            remove:           (...ids)       => self.remove(...ids),
            undo:             ()             => self.undo(),
            redo:             ()             => self.redo(),
            export:           ()             => self.export(),
            load:             (data)         => self.load(data),
            setZoom:          (z)            => self.setZoom(z),
            getZoom:          ()             => self.getZoom(),
            setArtboard:      (w, h)         => self.setArtboard(w, h),
            getArtboard:      ()             => self.getArtboard(),
            getSelected:      ()             => self.getSelected(),
            getElements:      ()             => self.getElements(),
            registerPlugin:   (p)            => self.registerPlugin(p),
            unregisterPlugin: (n)            => self.unregisterPlugin(n),
            destroy:          ()             => self.destroy(),
            get element()                       { return self.#container; },
            get destroyed()                     { return self.#destroyed; },
        };
    }

    // ── Plugin management ───────────────────────────────────────

    /**
     * Register a custom element plugin.
     * Accepts an object plugin or a string path to auto-load the module.
     * @param {Object|string} plugin - The plugin object or path to the plugin module.
     * @returns {Promise<void>} A promise that resolves when the plugin is registered.
     */
    async registerPlugin(plugin) {
        if (typeof plugin === 'string') {
            const mod = await this.#loadPluginModule(plugin);
            if (mod) {
                if (Array.isArray(mod)) mod.forEach(p => this.registerPlugin(p));
                else this.registerPlugin(mod);
            }
            return;
        }
        if (!plugin?.name) return;
        const ctx = this.#ctx();
        ctx.plugins = ctx.plugins.filter(p => p.name !== plugin.name);
        ctx.plugins.push(plugin);
        ctx.refreshPalette();
    }

    /** 
     * Load a plugin from a module path string. 
     * @param {string} path - The path to the plugin module.
     * @returns {Promise<Object|null>} A promise that resolves to the loaded plugin module, or null if loading fails.
     */
    async #loadPluginModule(path) {
        try {
            let url;
            if (path.includes('/') || path.includes('.')) {
                url = new URL(path, import.meta.url).href;
            } else {
                url = new URL(`../../plugins/LayoutEditor/${path}.js`, import.meta.url).href;
            }
            const mod = await import(url);
            return mod.default || mod;
        } catch (err) {
            console.warn('LayoutEditor: failed to load plugin \u2192', path, err);
            return null;
        }
    }

    /** 
     * Remove a registered plugin. 
     * @param {string} name - The name of the plugin to remove.
     */
    unregisterPlugin(name) {
        const ctx = this.#ctx();
        ctx.plugins = ctx.plugins.filter(p => p.name !== name);
        ctx.refreshPalette();
    }

    /** 
     * Get registered plugins. 
     * @returns {Object[]} An array of registered plugins.
     */
    getPlugins() { return [...this.#plugins]; }

    /**
     * Teardown — remove DOM, clear ColorPicker popups, null out refs.
     */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        // Abort all global event listeners
        this.#eventAC?.abort();

        // Destroy any active color picker popups
        this.#_cpInstances.forEach(cp => cp.destroy?.());
        this.#_cpInstances = [];

        // Remove root DOM
        if (this.#root) {
            this.#root.remove();
            this.#root = null;
        }

        this.#container = null;
        this.#_ctx = null;
    }
}

export default LayoutEditor;
