/**
 * @fileoverview LayoutEditor view — DOM construction, element rendering,
 *               layer panel, properties panel, palette, snap-guide overlay,
 *               zoom / pan transforms, grid toggle, isolation bar, and
 *               export popup.
 *
 * Every exported function receives the thin `ctx` context object produced
 * by the class's `#ctx()` bridge (see index.js).
 *
 * @module module/LayoutEditor/view
 */

import razyui from '../../index.js';
import Icons from '../Icons.js';
import { renderPluginProps, bindPluginProps, attachColorPickers, closeColorPopups } from '../_EditorProps.js';
import { ARTBOARD_PRESETS, RESIZE_HANDLES, LAYER_ICON_MAP, BUILTIN_PALETTE_ITEMS, PART } from './constants.js';
import { el, esc, normRect, findEl, updateGroupBounds, kebabStyle } from './helpers.js';

// ═══════════════════════════════════════════════
// DOM construction
// ═══════════════════════════════════════════════

/**
 * Build the entire LayoutEditor DOM tree inside `ctx.container`.
 * Populates DOM-ref properties on ctx (toolbar, canvas, artboard, etc.).
 * @param {Object} ctx
 */
export function buildDOM(ctx) {
    const container = ctx.container;
    const $container = razyui(container);
    $container.addClass('layout-editor le-root').html('');
    PART.ROOT.apply($container);

    // ── Toolbar ──
    ctx.toolbar = el('div', 'le-toolbar');
    PART.TOOLBAR.apply(ctx.toolbar);
    ctx.toolbar.html(`
        <div class="le-toolbar-group">
            <button class="le-tb-btn" data-action="undo" title="Undo (Ctrl+Z)">${Icons.svg('rotate-ccw', { size: 16, strokeWidth: 1.8 })}</button>
            <button class="le-tb-btn" data-action="redo" title="Redo (Ctrl+Y)">${Icons.svg('rotate-cw', { size: 16, strokeWidth: 1.8 })}</button>
        </div>
        <div class="le-toolbar-sep"></div>
        <div class="le-toolbar-group">
            <button class="le-tb-btn le-tb-sm" data-action="zoom-out" title="Zoom out">${Icons.svg('minus', { size: 14, strokeWidth: 2 })}</button>
            <span class="le-zoom-label">100%</span>
            <button class="le-tb-btn le-tb-sm" data-action="zoom-in" title="Zoom in">${Icons.svg('plus', { size: 14, strokeWidth: 2 })}</button>
            <button class="le-tb-btn le-tb-sm" data-action="zoom-fit" title="Fit to view">${Icons.svg('maximize-2', { size: 14, strokeWidth: 1.8 })}</button>
        </div>
        <div class="le-toolbar-sep"></div>
        <div class="le-toolbar-group">
            <span class="le-artboard-label" title="Artboard size">${ctx.artboardW} × ${ctx.artboardH}</span>
        </div>
        <div class="le-toolbar-sep"></div>
        <div class="le-toolbar-group">
            <button class="le-tb-btn le-tb-toggle le-tb-active" data-action="layers" title="Toggle Side Panel">${Icons.svg('menu', { size: 16, strokeWidth: 1.8 })}</button>
            <button class="le-tb-btn le-tb-toggle le-tb-active" data-action="props" title="Toggle Properties panel">${Icons.svg('settings', { size: 16, strokeWidth: 1.8 })}</button>
        </div>
        <div class="le-toolbar-sep"></div>
        <div class="le-toolbar-group">
            <button class="le-tb-btn" data-action="grid" title="Toggle grid">${Icons.svg('grid', { size: 16, strokeWidth: 1.8 })}</button>
            <button class="le-tb-btn" data-action="group" title="Group (Ctrl+G)">${Icons.svg('folder-plus', { size: 16, strokeWidth: 1.8 })}</button>
            <button class="le-tb-btn" data-action="ungroup" title="Ungroup (Ctrl+Shift+G)">${Icons.svg('folder-minus', { size: 16, strokeWidth: 1.8 })}</button>
            <button class="le-tb-btn" data-action="fullscreen" title="Fullscreen">${Icons.svg('maximize', { size: 16, strokeWidth: 1.8 })}</button>
            <button class="le-tb-btn" data-action="export" title="Export JSON">${Icons.svg('download', { size: 16, strokeWidth: 1.8 })}</button>
        </div>
    `);
    ctx.zoomLabel = ctx.toolbar.find('.le-zoom-label');
    $container.append(ctx.toolbar[0]);

    // ── Body (panels + canvas) ──
    const body = el('div', 'le-body');
    PART.BODY.apply(body);

    // Canvas viewport
    ctx.canvas = el('div', 'le-canvas');
    PART.CANVAS.apply(ctx.canvas);

    // Left panel (tabbed: Layers + Elements)
    ctx.layerPanel = el('div', 'le-layers');
    PART.LAYERS.apply(ctx.layerPanel);
    const leftTabs = el('div', 'le-left-tabs');
    PART.LEFT_TABS.apply(leftTabs);
    leftTabs.html(`<button class="le-left-tab is-active" data-left-tab="layers">Layers</button><button class="le-left-tab" data-left-tab="elements">Elements</button>`);
    ctx.layerPanel.append(leftTabs);
    const layerContent = el('div', 'le-left-content le-left-layers is-active');
    PART.LEFT_CONTENT.apply(layerContent);
    layerContent.html(`<div class="le-layer-list"></div>`);
    ctx.layerPanel.append(layerContent);

    // Palette content inside the same panel
    ctx.palettePanel = el('div', 'le-left-content le-left-elements');
    PART.LEFT_CONTENT.apply(ctx.palettePanel);
    ctx.palettePanel.html(`<div class="le-palette-list"></div>`);
    ctx.layerPanel.append(ctx.palettePanel);
    ctx.canvas.append(ctx.layerPanel);

    // Floating tab to reopen left panel
    const layersTab = el('button', 'le-panel-tab le-panel-tab-left le-panel-tab-hidden');
    PART.PANEL_TAB.apply(layersTab);
    layersTab.data('panelTab', 'layers');
    layersTab.attr('title', 'Show Side Panel');
    layersTab.html(Icons.svg('menu', { size: 16, strokeWidth: 1.8 }));
    ctx.canvas.append(layersTab);

    // Artboard
    ctx.artboard = el('div', 'le-artboard');
    PART.ARTBOARD.apply(ctx.artboard);
    ctx.artboard.css('width', ctx.artboardW + 'px');
    ctx.artboard.css('height', ctx.artboardH + 'px');

    // Grid overlay
    const gridOvl = el('div', 'le-grid-overlay');
    PART.GRID_OVERLAY.apply(gridOvl);
    ctx.artboard.append(gridOvl);
    if (ctx.config.showGrid !== false) gridOvl.addClass('le-visible');
    gridOvl.css('background-size', `${ctx.gridSize}px ${ctx.gridSize}px`);

    // Guides overlay
    ctx.guidesOverlay = el('div', 'le-guides-overlay');
    PART.GUIDES_OVERLAY.apply(ctx.guidesOverlay);
    ctx.artboard.append(ctx.guidesOverlay);

    // Selection rubber-band
    ctx.selectionBox = el('div', 'le-selection-box');
    PART.SELECTION_BOX.apply(ctx.selectionBox);
    ctx.artboard.append(ctx.selectionBox);

    ctx.canvas.append(ctx.artboard);

    // Properties panel (floating inside canvas)
    ctx.propPanel = el('div', 'le-props');
    PART.PROPS.apply(ctx.propPanel);
    ctx.propPanel.html(`<div class="le-panel-header"><span>Properties</span><button class="le-panel-close" data-action="props" title="Close">${Icons.svg('x', { size: 14, strokeWidth: 2 })}</button></div><div class="le-prop-body"><p class="le-prop-empty">Select an element</p></div>`);
    ctx.canvas.append(ctx.propPanel);

    // Floating tab to reopen properties
    const propsTab = el('button', 'le-panel-tab le-panel-tab-right le-panel-tab-hidden');
    PART.PANEL_TAB.apply(propsTab);
    propsTab.data('panelTab', 'props');
    propsTab.attr('title', 'Show Properties');
    propsTab.html(Icons.svg('settings', { size: 16, strokeWidth: 1.8 }));
    ctx.canvas.append(propsTab);

    body.append(ctx.canvas);

    // Context menu (appended to body, positioned absolute)
    ctx.contextMenuEl = el('div', 'le-context-menu le-context-hidden');
    PART.CONTEXT_MENU.apply(ctx.contextMenuEl);
    body.append(ctx.contextMenuEl);

    $container.append(body[0]);
}

// ═══════════════════════════════════════════════
// Element rendering
// ═══════════════════════════════════════════════

/**
 * Render (or update) a single layout element's DOM node.
 * @param {Object} elData — element model object
 * @param {Object} ctx
 */
export function renderElement(elData, ctx) {
    let dom = ctx.artboard.find(`[data-le-id="${elData.id}"]`);
    if (!dom.length) {
        dom = el('div', 'le-element');
        PART.ELEMENT.apply(dom);
        dom.data('leId', elData.id);
        dom.data('leType', elData.type);

        // Resize handles (not for groups)
        if (elData.type !== 'group') {
            RESIZE_HANDLES.forEach(h => {
                const handle = el('div', `le-handle le-handle-${h}`);
                PART.HANDLE.apply(handle);
                handle.data('handle', h);
                dom.append(handle);
            });
        }

        // Content area
        const content = el('div', 'le-el-content');
        PART.EL_CONTENT.apply(content);
        dom.append(content);

        ctx.artboard.append(dom);
    }

    // Position & size
    if (elData.type === 'group') {
        updateGroupBounds(elData, ctx.elements);
    }
    dom.css('left', elData.x + 'px')
       .css('top', elData.y + 'px')
       .css('width', elData.w + 'px')
       .css('height', elData.h + 'px')
       .css('transform', elData.rotation ? `rotate(${elData.rotation}deg)` : '')
       .css('display', elData.visible ? '' : 'none');
    dom.toggleClass('le-locked', elData.locked);
    dom.toggleClass('le-group', elData.type === 'group');

    // Apply styles
    const content = dom.find('.le-el-content');
    if (elData.type === 'group') {
        content.attr('style', '');
        content.attr('class', 'le-el-content le-group-content');
    } else {
        content.css(kebabStyle(elData.style || {}));
    }

    // Type-specific content rendering
    if (elData.type === 'text') {
        content.attr('contenteditable', elData.locked ? 'false' : 'true');
        content.addClass('le-text-content');
        if (!content.text() && elData.content) content.text(elData.content);
    } else if (elData.type === 'button') {
        content.addClass('le-btn-content')
               .text(elData.content || 'Button');
    } else if (elData.type === 'image') {
        content.addClass('le-img-content');
        if (elData.content) {
            content.css('background-image', `url(${elData.content})`)
                   .css('background-size', 'cover');
            content.css('background-position', 'center');
        } else {
            content.html('<span class="le-img-placeholder">' + Icons.svg('image', { size: 16, strokeWidth: 1.5 }) + ' Click to add image</span>');
        }
    } else if (elData.type === 'divider') {
        content.addClass('le-divider-content');
    } else if (elData.type === 'plugin') {
        content.addClass('le-plugin-content');
        const plugin = ctx.plugins.find(p => p.name === elData.pluginName);
        if (plugin && typeof plugin.render === 'function') {
            try { plugin.render(content[0], elData); } catch (e) { console.warn('LayoutEditor: plugin render error \u2192', elData.pluginName, e); }
        } else {
            content.html(`<span class="le-plugin-placeholder">${Icons.svg('grid', { size: 14, strokeWidth: 1.5 })} ${esc(elData.pluginName || 'Plugin')}</span>`);
        }
    }

    // Selection state
    dom.toggleClass('le-selected', ctx.selected.has(elData.id));
}

/**
 * Full re-render — remove all element DOM and rebuild.
 * @param {Object} ctx
 */
export function fullRender(ctx) {
    ctx.artboard.find('.le-element').forEach(d => d.remove());
    ctx.elements.forEach(e => renderElement(e, ctx));
    refreshLayers(ctx);
    refreshProps(ctx);
    refreshGuides(ctx);
}

// ═══════════════════════════════════════════════
// Selection
// ═══════════════════════════════════════════════

/**
 * Set the selection to exactly the given IDs.
 * @param {string[]} ids
 * @param {Object} ctx
 */
export function setSelected(ids, ctx) {
    ctx.selected.clear();
    ids.forEach(id => ctx.selected.add(id));
    ctx.artboard.find('.le-element').each(dom => {
        razyui(dom).toggleClass('le-selected', ctx.selected.has(dom.dataset.leId));
    });
    refreshProps(ctx);
    refreshLayers(ctx);
}

/**
 * Toggle selection of a single element.
 * @param {string} id
 * @param {boolean} add — multi-select mode
 * @param {Object} ctx
 */
export function toggleSelect(id, add, ctx) {
    if (add) {
        if (ctx.selected.has(id)) ctx.selected.delete(id);
        else ctx.selected.add(id);
    } else {
        if (ctx.selected.has(id) && ctx.selected.size === 1) return;
        ctx.selected.clear();
        ctx.selected.add(id);
    }
    ctx.artboard.find('.le-element').each(dom => {
        razyui(dom).toggleClass('le-selected', ctx.selected.has(dom.dataset.leId));
    });
    refreshProps(ctx);
    refreshLayers(ctx);
}

// ═══════════════════════════════════════════════
// Snap guides overlay
// ═══════════════════════════════════════════════

/**
 * Render active snap guides into the overlay.
 * @param {Object} ctx
 */
export function refreshGuides(ctx) {
    ctx.guidesOverlay.html('');
    ctx.guides.forEach(g => {
        const line = el('div', `le-guide le-guide-${g.axis}`);
        PART.GUIDE.apply(line);
        if (g.axis === 'x') {
            line.css('left', g.pos + 'px')
                .css('top', '0');
            line.css('height', '100%');
        } else {
            line.css('top', g.pos + 'px')
                .css('left', '0');
            line.css('width', '100%');
        }
        ctx.guidesOverlay.append(line);
    });
}

/**
 * Clear all snap guides.
 * @param {Object} ctx
 */
export function clearGuides(ctx) {
    ctx.guides = [];
    ctx.guidesOverlay.html('');
}

// ═══════════════════════════════════════════════
// Layer panel
// ═══════════════════════════════════════════════

/**
 * Rebuild the entire layer list.
 * @param {Object} ctx
 */
export function refreshLayers(ctx) {
    const list = ctx.layerPanel.find('.le-layer-list');
    list.html('');

    // Build set of IDs that are children of a group
    const childIds = new Set();
    ctx.elements.forEach(e => {
        if (e.type === 'group' && e.children) {
            e.children.forEach(cid => childIds.add(cid));
        }
    });

    // Render in reverse (top layer first), skipping group children
    for (let i = ctx.elements.length - 1; i >= 0; i--) {
        const e = ctx.elements[i];
        if (childIds.has(e.id)) continue;
        renderLayerRow(list, e, 0, ctx);
    }
}

/**
 * Render a single layer row (recursively renders group children).
 * @param {HTMLElement} container
 * @param {Object} elData
 * @param {number} depth — indent level
 * @param {Object} ctx
 */
function renderLayerRow(container, elData, depth, ctx) {
    const row = el('div', 'le-layer-row');
    PART.LAYER_ROW.apply(row);
    row.toggleClass('le-layer-selected', ctx.selected.has(elData.id));
    row.data('leId', elData.id);
    if (depth > 0) row.css('padding-left', (8 + depth * 16) + 'px');

    const icon = LAYER_ICON_MAP[elData.type] || '▢';
    const groupToggle = elData.type === 'group' ? `<span class="le-layer-group-toggle">${Icons.svg('chevron-down', { size: 12, strokeWidth: 2 })}</span>` : '';
    const isCollapsed = ctx.collapsedGroups.has(elData.id);
    if (isCollapsed) row.addClass('le-layer-collapsed');
    row.html(`
        ${groupToggle}
        <span class="le-layer-icon">${icon}</span>
        <span class="le-layer-name">${elData.name || elData.type}</span>
        <button class="le-layer-vis ${elData.visible ? '' : 'le-layer-hidden'}" data-id="${elData.id}" title="Toggle visibility">${Icons.svg('eye', { size: 12, strokeWidth: 1.5 })}</button>
        <button class="le-layer-lock ${elData.locked ? 'le-layer-locked' : ''}" data-id="${elData.id}" title="Toggle lock">${Icons.svg('lock', { size: 12, strokeWidth: 1.5 })}</button>
    `);

    // Draggable for layer reorder (events delegated in events.js)
    row.attr('draggable', 'true');

    container.append(row);

    // Render children of groups
    if (elData.type === 'group' && elData.children && !ctx.collapsedGroups.has(elData.id)) {
        for (let i = elData.children.length - 1; i >= 0; i--) {
            const child = findEl(elData.children[i], ctx.elements);
            if (child) renderLayerRow(container, child, depth + 1, ctx);
        }
    }
}

// ═══════════════════════════════════════════════
// Properties panel
// ═══════════════════════════════════════════════

/**
 * Update the artboard dimension label in the toolbar.
 * @param {Object} ctx
 */
export function updateArtboardLabel(ctx) {
    const label = ctx.toolbar.find('.le-artboard-label');
    if (label.length) label.text(`${ctx.artboardW} × ${ctx.artboardH}`);
}

/**
 * Render artboard properties (preset, W/H, grid, snap) into `body`.
 * @param {HTMLElement} body
 * @param {Object} ctx
 */
function renderArtboardProps(body, ctx) {
    const presets = ARTBOARD_PRESETS;
    const match = presets.find(p => p.w === ctx.artboardW && p.h === ctx.artboardH);
    const presetVal = match ? `${match.w}x${match.h}` : 'custom';

    body.html(`
        <div class="le-prop-section-title">Artboard</div>
        <div class="le-prop-section">
            <label class="le-prop-label">Preset</label>
            <select class="le-prop-input" data-artboard="preset">
                ${presets.map(p => `<option value="${p.w}x${p.h}" ${presetVal === `${p.w}x${p.h}` ? 'selected' : ''}>${p.label}  (${p.w}×${p.h})</option>`).join('')}
                <option value="custom" ${presetVal === 'custom' ? 'selected' : ''}>Custom</option>
            </select>
        </div>
        <div class="le-prop-section le-prop-row">
            <div class="le-prop-field">
                <label class="le-prop-label">Width</label>
                <input class="le-prop-input" type="number" data-artboard="w" value="${ctx.artboardW}" min="100">
            </div>
            <div class="le-prop-field">
                <label class="le-prop-label">Height</label>
                <input class="le-prop-input" type="number" data-artboard="h" value="${ctx.artboardH}" min="100">
            </div>
        </div>
        <div class="le-prop-section">
            <label class="le-prop-label">Grid Size</label>
            <input class="le-prop-input" type="number" data-artboard="grid" value="${ctx.gridSize}" min="5" max="200">
        </div>
        <div class="le-prop-section le-prop-row">
            <label style="display:flex;align-items:center;gap:6px;font-size:12px;cursor:pointer">
                <input type="checkbox" data-artboard="snap-grid" ${ctx.snapToGrid ? 'checked' : ''}>
                Snap to grid
            </label>
            <label style="display:flex;align-items:center;gap:6px;font-size:12px;cursor:pointer">
                <input type="checkbox" data-artboard="snap-guides" ${ctx.snapGuides ? 'checked' : ''}>
                Snap guides
            </label>
        </div>
    `);

    // Event bindings are delegated from propBody in events.js
}

/**
 * Render style properties HTML for a given element.
 * @param {Object} elData
 * @param {Object} ctx
 * @returns {string} HTML string
 */
function renderStyleProps(elData, ctx) {
    let html = '<div class="le-prop-divider"></div>';
    html += '<div class="le-prop-section-title">Style</div>';

    // Background
    html += `<div class="le-prop-section">
        <label class="le-prop-label">Background</label>
        <div class="le-prop-color-wrap">
            <span class="le-prop-color-swatch" data-color-for="background" style="background:${esc(elData.style?.background || 'transparent')}"></span>
            <input class="le-prop-input le-prop-full" type="text" data-style-prop="background" value="${esc(elData.style?.background || '')}">
        </div>
    </div>`;

    // Border radius
    const radiusNum = parseInt(elData.style?.borderRadius) || 0;
    html += `<div class="le-prop-section">
        <label class="le-prop-label">Radius</label>
        <div class="le-prop-slider-wrap">
            <input class="le-prop-slider" type="range" data-slider-for="borderRadius" data-slider-style="1" min="0" max="100" step="1" value="${radiusNum}">
            <input class="le-prop-input le-prop-slider-num" type="text" data-style-prop="borderRadius" value="${esc(elData.style?.borderRadius || '')}">
        </div>
    </div>`;

    // Border
    html += `<div class="le-prop-section">
        <label class="le-prop-label">Border</label>
        <input class="le-prop-input le-prop-full" type="text" data-style-prop="border" value="${esc(elData.style?.border || '')}">
    </div>`;

    // Text-specific props
    if (elData.type === 'text' || elData.type === 'button') {
        html += '<div class="le-prop-divider"></div><div class="le-prop-section-title">Typography</div>';
        const fsNum = parseInt(elData.style?.fontSize) || 16;
        html += `<div class="le-prop-section">
            <label class="le-prop-label">Font Size</label>
            <div class="le-prop-slider-wrap">
                <input class="le-prop-slider" type="range" data-slider-for="fontSize" data-slider-style="1" min="8" max="120" step="1" value="${fsNum}">
                <input class="le-prop-input le-prop-slider-num" type="text" data-style-prop="fontSize" value="${esc(elData.style?.fontSize || '16px')}">
            </div>
        </div>`;
        html += `<div class="le-prop-section">
            <label class="le-prop-label">Color</label>
            <div class="le-prop-color-wrap">
                <span class="le-prop-color-swatch" data-color-for="color" style="background:${esc(elData.style?.color || '#fff')}"></span>
                <input class="le-prop-input" type="text" data-style-prop="color" value="${esc(elData.style?.color || '#fff')}">
            </div>
        </div>`;
        const fwVal = elData.style?.fontWeight || '400';
        html += `<div class="le-prop-section">
            <label class="le-prop-label">Font Weight</label>
            <div class="le-prop-btngroup" data-style-prop="fontWeight">
                <button class="le-prop-btn${fwVal === '300' ? ' le-prop-btn-active' : ''}" data-val="300">Light</button>
                <button class="le-prop-btn${fwVal === '400' ? ' le-prop-btn-active' : ''}" data-val="400">Regular</button>
                <button class="le-prop-btn${fwVal === '600' ? ' le-prop-btn-active' : ''}" data-val="600">Semi</button>
                <button class="le-prop-btn${fwVal === '700' ? ' le-prop-btn-active' : ''}" data-val="700">Bold</button>
            </div>
        </div>`;
        const taVal = elData.style?.textAlign || 'left';
        html += `<div class="le-prop-section">
            <label class="le-prop-label">Text Align</label>
            <div class="le-prop-btngroup" data-style-prop="textAlign">
                <button class="le-prop-btn${taVal === 'left' ? ' le-prop-btn-active' : ''}" data-val="left" title="Left">&#9776;</button>
                <button class="le-prop-btn${taVal === 'center' ? ' le-prop-btn-active' : ''}" data-val="center" title="Center">&#9866;</button>
                <button class="le-prop-btn${taVal === 'right' ? ' le-prop-btn-active' : ''}" data-val="right" title="Right">&#9783;</button>
            </div>
        </div>`;
    }

    // Image URL
    if (elData.type === 'image') {
        html += '<div class="le-prop-divider"></div>';
        html += `<div class="le-prop-section">
            <label class="le-prop-label">Image URL</label>
            <input class="le-prop-input le-prop-full" type="text" data-prop="content" value="${esc(elData.content)}" placeholder="https://...">
        </div>`;
    }

    // Opacity
    const opVal = elData.style?.opacity ?? 1;
    html += `<div class="le-prop-section">
        <label class="le-prop-label">Opacity</label>
        <div class="le-prop-slider-wrap">
            <input class="le-prop-slider" type="range" data-slider-for="opacity" data-slider-style="1" min="0" max="1" step="0.05" value="${opVal}">
            <input class="le-prop-input le-prop-slider-num" type="number" data-style-prop="opacity" value="${opVal}" min="0" max="1" step="0.05">
        </div>
    </div>`;

    // Plugin properties
    if (elData.type === 'plugin' && elData.pluginName) {
        const plugin = ctx.plugins.find(p => p.name === elData.pluginName);
        if (plugin?.properties?.length) {
            html += '<div class="le-prop-divider"></div>';
            html += `<div class="le-prop-section-title">${esc(plugin.label || plugin.name)} Properties</div>`;
            if (!elData.pluginProps) elData.pluginProps = {};
            html += renderPluginProps(plugin.properties, elData.pluginProps, 'le');
        }
    }

    return html;
}

/**
 * Refresh the properties panel (artboard props when nothing selected,
 * element props when one selected, multi-select count otherwise).
 * @param {Object} ctx
 */
export function refreshProps(ctx) {
    const body = ctx.propPanel.find('.le-prop-body');
    if (ctx.selected.size === 0) {
        renderArtboardProps(body, ctx);
        return;
    }
    if (ctx.selected.size > 1) {
        body.html(`<p class="le-prop-empty">${ctx.selected.size} elements selected</p>`);
        return;
    }
    const id = [...ctx.selected][0];
    const elData = findEl(id, ctx.elements);
    if (!elData) return;

    body.html(`
        <div class="le-prop-section">
            <label class="le-prop-label">Name</label>
            <input class="le-prop-input le-prop-full" type="text" data-prop="name" value="${esc(elData.name)}">
        </div>
        <div class="le-prop-section le-prop-row">
            <div class="le-prop-field">
                <label class="le-prop-label">X</label>
                <input class="le-prop-input" type="number" data-prop="x" value="${Math.round(elData.x)}">
            </div>
            <div class="le-prop-field">
                <label class="le-prop-label">Y</label>
                <input class="le-prop-input" type="number" data-prop="y" value="${Math.round(elData.y)}">
            </div>
        </div>
        <div class="le-prop-section le-prop-row">
            <div class="le-prop-field">
                <label class="le-prop-label">W</label>
                <input class="le-prop-input" type="number" data-prop="w" value="${Math.round(elData.w)}">
            </div>
            <div class="le-prop-field">
                <label class="le-prop-label">H</label>
                <input class="le-prop-input" type="number" data-prop="h" value="${Math.round(elData.h)}">
            </div>
        </div>
        <div class="le-prop-section">
            <div class="le-prop-field">
                <label class="le-prop-label">Rotation</label>
                <div class="le-prop-slider-wrap">
                    <input class="le-prop-slider" type="range" data-slider-for="rotation" min="0" max="360" step="1" value="${elData.rotation || 0}">
                    <input class="le-prop-input le-prop-slider-num" type="number" data-prop="rotation" value="${elData.rotation || 0}" step="1" min="0" max="360">
                </div>
            </div>
        </div>
        ${renderStyleProps(elData, ctx)}
    `);

    // Prop input / slider / button-group events are delegated from propBody in events.js

    // Attach ColorPicker popups to swatches
    attachColorPickersForEl(body, elData, ctx);

    // Bind plugin property inputs
    bindPluginProps(body, elData, {
        pushUndo: () => ctx.pushUndo(),
        onChange: () => { renderElement(elData, ctx); ctx.onChange(); }
    });
}

/** @private Attach color picker instances to swatches in the props panel. */
async function attachColorPickersForEl(body, elData, ctx) {
    await attachColorPickers(body, elData, {
        prefix: 'le',
        styleAttr: 'style-prop',
        container: ctx.container,
        instances: ctx._cpInstances,
        pushUndo: () => ctx.pushUndo(),
        onChange: () => { renderElement(elData, ctx); ctx.onChange(); }
    });
}

/**
 * Close all open ColorPicker popups.
 * @param {Object} ctx
 */
export function closeColorPopupsCtx(ctx) {
    closeColorPopups(ctx._cpInstances);
}

/**
 * Lightweight prop-value sync — update input values without rebuilding DOM.
 * @param {Object} ctx
 */
export function updatePropValues(ctx) {
    if (ctx.selected.size !== 1) return;
    const elData = findEl([...ctx.selected][0], ctx.elements);
    if (!elData) return;
    const body = ctx.propPanel.find('.le-prop-body');
    if (!body.length) return;
    body.find('.le-prop-input').forEach(input => {
        const prop = input.dataset.prop;
        if (!prop) return;
        if (document.activeElement === input) return; // don't overwrite while user is typing
        const val = ['x','y','w','h'].includes(prop) ? Math.round(elData[prop]) : (elData[prop] ?? '');
        if (input.value !== String(val)) input.value = val;
    });
}

