/**
 * Rebuild the elements palette panel (built-in types + registered plugins).
 * @param {Object} ctx
 */
export function refreshPalette(ctx) {
    if (!ctx.palettePanel) return;
    const list = ctx.palettePanel.find('.le-palette-list');
    list.html('');

    // Section: Built-in
    const builtinTitle = el('div', 'le-palette-section-title');
    PART.PALETTE_TITLE.apply(builtinTitle);
    builtinTitle.text('Basic');
    list.append(builtinTitle);

    BUILTIN_PALETTE_ITEMS.forEach(item => {
        const chip = el('div', 'le-palette-item');
        PART.PALETTE_ITEM.apply(chip);
        chip.attr('draggable', 'true');
        chip.data('paletteName', item.name);
        chip.data('paletteType', 'builtin');
        chip.html(`<span class="le-palette-icon">${item.icon}</span><span class="le-palette-label">${item.label}</span>`);
        list.append(chip);
    });

    // Section: Plugins
    if (ctx.plugins.length) {
        const pluginTitle = el('div', 'le-palette-section-title');
        PART.PALETTE_TITLE.apply(pluginTitle);
        pluginTitle.text('Components');
        list.append(pluginTitle);

        ctx.plugins.forEach(plugin => {
            const chip = el('div', 'le-palette-item');
            PART.PALETTE_ITEM.apply(chip);
            chip.attr('draggable', 'true');
            chip.data('paletteName', plugin.name);
            chip.data('paletteType', 'plugin');
            chip.html(`<span class="le-palette-icon">${plugin.icon || Icons.svg('grid', { size: 16, strokeWidth: 1.5 })}</span><span class="le-palette-label">${plugin.label || plugin.name}</span>`);
            list.append(chip);
        });
    }
}

