// ═══════════════════════════════════════════════
// Zoom / pan
// ═══════════════════════════════════════════════

/**
 * Set zoom level, optionally anchoring around a client point.
 * @param {number} z — new zoom (will be clamped 0.1–5)
 * @param {number} [cx] — anchor clientX
 * @param {number} [cy] — anchor clientY
 * @param {Object} ctx
 */
export function setZoom(z, cx, cy, ctx) {
    const oldZ = ctx.zoom;
    ctx.zoom = Math.max(0.1, Math.min(5, z));
    ctx.zoomLabel.text(Math.round(ctx.zoom * 100) + '%');

    if (cx !== undefined && cy !== undefined) {
        const rect = ctx.canvas.getRect();
        const ox = cx - rect.left;
        const oy = cy - rect.top;
        ctx.panX = ox - (ox - ctx.panX) * (ctx.zoom / oldZ);
        ctx.panY = oy - (oy - ctx.panY) * (ctx.zoom / oldZ);
    }

    applyTransform(ctx);
}

/**
 * Apply the current pan + zoom transform to the artboard.
 * @param {Object} ctx
 */
export function applyTransform(ctx) {
    ctx.artboard.css('transform', `translate(${ctx.panX}px, ${ctx.panY}px) scale(${ctx.zoom})`);
}

/**
 * Center the artboard in the canvas viewport.
 * @param {Object} ctx
 */
export function centerArtboard(ctx) {
    const rect = ctx.canvas.getRect();
    ctx.panX = (rect.width - ctx.artboardW * ctx.zoom) / 2;
    ctx.panY = (rect.height - ctx.artboardH * ctx.zoom) / 2;
    applyTransform(ctx);
}

/**
 * Fit the artboard into the viewport with padding.
 * @param {Object} ctx
 */
export function fitToView(ctx) {
    const rect = ctx.canvas.getRect();
    const pad = 60;
    const scaleX = (rect.width - pad * 2) / ctx.artboardW;
    const scaleY = (rect.height - pad * 2) / ctx.artboardH;
    ctx.zoom = Math.min(scaleX, scaleY, 2);
    ctx.zoomLabel.text(Math.round(ctx.zoom * 100) + '%');
    centerArtboard(ctx);
}

