/**
 * Show the JSON export popup.
 * @param {Object} ctx
 */
export function exportJSON(ctx) {
    const data = ctx.exportData();
    const json = JSON.stringify(data, null, 2);

    // Remove existing export popup
    razyui(ctx.container).find('.le-export-popup')[0]?.remove();

    const overlay = el('div', 'le-export-popup');
    PART.EXPORT_POPUP.apply(overlay);
    overlay.html(`
        <div class="le-export-dialog">
            <div class="le-export-header">
                <span class="le-export-title">Export JSON</span>
                <button class="le-export-close" title="Close">${Icons.svg('x', { size: 16, strokeWidth: 2 })}</button>
            </div>
            <textarea class="le-export-code" readonly spellcheck="false">${esc(json)}</textarea>
            <div class="le-export-actions">
                <button class="le-export-btn le-export-copy">${Icons.svg('clipboard', { size: 14, strokeWidth: 1.5 })} Copy</button>
                <button class="le-export-btn le-export-download">${Icons.svg('download', { size: 14, strokeWidth: 1.5 })} Download</button>
            </div>
        </div>
    `);

    // Close
    overlay.find('.le-export-close').on('click', () => overlay[0].remove());
    overlay.on('click', (e) => { if (e.target === overlay[0]) overlay[0].remove(); });

    // Copy
    overlay.find('.le-export-copy').on('click', () => {
        navigator.clipboard?.writeText(json);
        const btn = overlay.find('.le-export-copy');
        btn.html(Icons.svg('check', { size: 14, strokeWidth: 2 }) + ' Copied!');
        setTimeout(() => btn.html(Icons.svg('clipboard', { size: 14, strokeWidth: 1.5 }) + ' Copy'), 1500);
    });

    // Download
    overlay.find('.le-export-download').on('click', () => {
        const blob = new Blob([json], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = ctx.razyui.el('a', { href: url, download: 'layout.json' });
        a.trigger('click');
        URL.revokeObjectURL(url);
    });

    razyui(ctx.container).append(overlay[0]);
    // Select all text for easy copying
    const ta = overlay.find('.le-export-code');
    ta.focus();
    ta[0].select();
}
